"use client"

import { useState, useEffect } from "react";
import Link from "next/link";
import ScraperStatusTable from "@/components/ScraperStatusTable";
import CsvUploadFallback from "@/components/CsvUploadFallback";

const PLATFORM_LIST = [
    { id: 1, name: "Revu" },
    { id: 2, name: "Reviewnote" },
    { id: 3, name: "DinnerQueen" },
    { id: 4, name: "ReviewPlace" },
    { id: 5, name: "Seouloppa" },
    { id: 6, name: "MrBlog" },
    { id: 7, name: "GangnamFood" },
];

type IngestStatus = 'idle' | 'triggering' | 'success' | 'error';

export default function AdminDashboard() {
    const [runs, setRuns] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedPlatformId, setSelectedPlatformId] = useState<number | 'all'>('all');
    const [ingestStatus, setIngestStatus] = useState<IngestStatus>('idle');
    const [ingestMessage, setIngestMessage] = useState('');
    const [healthStatus, setHealthStatus] = useState<'ok' | 'error' | 'checking'>('checking');
    const [totalCampaigns, setTotalCampaigns] = useState<number | null>(null);

    // Fetch Runs
    const fetchRuns = async () => {
        try {
            const res = await fetch('/api/admin/runs?limit=30');
            if (!res.ok) throw new Error('Runs API failed');
            const data = await res.json();
            if (data.data) setRuns(data.data);
        } catch (e) {
            console.error("Failed to fetch runs", e);
        } finally {
            setIsLoading(false);
        }
    };

    // Health Check
    const checkHealth = async () => {
        try {
            const [healthRes, campRes] = await Promise.all([
                fetch('/api/health'),
                fetch('/api/campaigns?limit=1'),
            ]);

            const healthData = await healthRes.json();

            if (healthRes.ok && healthData?.db === 'ok') {
                setHealthStatus('ok');
            } else {
                setHealthStatus('error');
            }

            if (campRes.ok) {
                const campData = await campRes.json();
                setTotalCampaigns(campData?.meta?.total ?? 0);
            } else {
                setTotalCampaigns(0);
            }
        } catch {
            setHealthStatus('error');
        }
    };

    // Trigger Ingest
    const triggerIngest = async () => {
        if (ingestStatus === 'triggering') return;
        setIngestStatus('triggering');
        setIngestMessage('');

        const platformsToIngest = selectedPlatformId === 'all'
            ? PLATFORM_LIST
            : PLATFORM_LIST.filter(p => p.id === selectedPlatformId);

        try {
            const results = await Promise.all(
                platformsToIngest.map(p =>
                    fetch('/api/admin/ingest', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ platform_id: p.id })
                    }).then(r => r.ok ? `Queued ${p.name}` : `Failed ${p.name}`)
                )
            );
            setIngestStatus('success');
            setIngestMessage(results.join('  |  '));
            // Poll for updated status after 2s
            setTimeout(fetchRuns, 2000);
            setTimeout(fetchRuns, 6000);
        } catch (e: any) {
            setIngestStatus('error');
            setIngestMessage(e?.message || 'Unexpected ingest error occurred.');
        } finally {
            setTimeout(() => setIngestStatus('idle'), 8000);
        }
    };

    useEffect(() => {
        fetchRuns();
        checkHealth();
        const runsTimer = setInterval(fetchRuns, 10000);
        const healthTimer = setInterval(checkHealth, 30000);
        return () => {
            clearInterval(runsTimer);
            clearInterval(healthTimer);
        };
    }, []);

    // Stats
    const successRuns = runs.filter(r => r.status === 'SUCCESS').length;
    const failedRuns = runs.filter(r => r.status === 'FAILED').length;
    const runningRuns = runs.filter(r => r.status === 'RUNNING').length;

    return (
        <div className="max-w-7xl mx-auto p-4 md:p-8 flex flex-col gap-6 pb-32">
            <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-black tracking-tight text-slate-900 flex items-center gap-3">
                        Campaign Scraper Admin
                        <span className="relative flex h-3 w-3">
                            <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${healthStatus === 'ok' ? 'bg-green-400' : 'bg-red-400'}`}></span>
                            <span className={`relative inline-flex rounded-full h-3 w-3 ${healthStatus === 'ok' ? 'bg-green-500' : healthStatus === 'checking' ? 'bg-amber-400' : 'bg-red-500'}`}></span>
                        </span>
                    </h1>
                    <p className="text-sm text-slate-500 mt-1 font-medium">Monitor and control campaign ingestion jobs in one place.</p>
                </div>
                <Link
                    href="/"
                    className="text-sm font-bold text-slate-500 hover:text-blue-600 transition flex items-center gap-1.5 px-4 py-2 border border-slate-200 rounded-xl hover:border-blue-300 bg-white shadow-sm"
                >
                    Back to Home
                </Link>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                {[
                    {
                        label: 'System Status',
                        value: healthStatus === 'ok' ? 'ONLINE' : healthStatus === 'checking' ? 'CHECKING' : 'OFFLINE',
                        color: healthStatus === 'ok' ? 'text-green-600' : healthStatus === 'checking' ? 'text-amber-500' : 'text-red-600',
                        bg: healthStatus === 'ok' ? 'bg-green-50' : healthStatus === 'checking' ? 'bg-amber-50' : 'bg-red-50',
                    },
                    {
                        label: 'Total Campaigns',
                        value: totalCampaigns !== null ? `${totalCampaigns.toLocaleString()}` : '0',
                        color: 'text-blue-600',
                        bg: 'bg-blue-50',
                    },
                    {
                        label: 'Success Runs',
                        value: `${successRuns}`,
                        color: 'text-emerald-600',
                        bg: 'bg-emerald-50',
                    },
                    {
                        label: 'Failed/Running',
                        value: `${failedRuns} / ${runningRuns}`,
                        color: failedRuns > 0 ? 'text-red-600' : 'text-slate-600',
                        bg: failedRuns > 0 ? 'bg-red-50' : 'bg-slate-50',
                    },
                ].map(stat => (
                    <div key={stat.label} className={`${stat.bg} rounded-2xl p-4 border border-white`}>
                        <div className="text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">{stat.label}</div>
                        <div className={`text-xl font-black ${stat.color}`}>{stat.value}</div>
                    </div>
                ))}
            </div>

            <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 flex flex-col gap-5">
                <div>
                    <h2 className="text-lg font-black text-slate-900">Ingest Control Panel</h2>
                    <p className="text-sm text-slate-500 mt-0.5">Choose one platform and run an ingest to refresh campaign data.</p>
                </div>
                <div className="flex flex-wrap gap-3">
                    <button
                        onClick={() => setSelectedPlatformId('all')}
                        className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${selectedPlatformId === 'all' ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-600 border-slate-200 hover:border-slate-400'}`}
                    >
                        All Platforms
                    </button>
                    {PLATFORM_LIST.map(p => (
                        <button
                            key={p.id}
                            onClick={() => setSelectedPlatformId(p.id)}
                            className={`px-4 py-2 rounded-xl text-sm font-bold border transition-all ${selectedPlatformId === p.id ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-600 border-slate-200 hover:border-blue-300'}`}
                        >
                            {p.name}
                        </button>
                    ))}
                </div>
                <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
                    <button
                        onClick={triggerIngest}
                        disabled={ingestStatus === 'triggering'}
                        className={`px-8 py-3.5 rounded-xl font-black text-sm transition-all shadow-sm ${ingestStatus === 'triggering'
                            ? 'bg-slate-100 text-slate-400 cursor-not-allowed'
                            : 'bg-blue-600 text-white hover:bg-blue-700 hover:-translate-y-0.5 hover:shadow-md'
                            }`}
                    >
                        {ingestStatus === 'triggering' ? 'Starting ingest...' : `${selectedPlatformId === 'all' ? 'Run all' : PLATFORM_LIST.find(p => p.id === selectedPlatformId)?.name} Ingest`}
                    </button>
                    {ingestMessage && (
                        <div className={`text-xs font-mono px-4 py-2 rounded-xl ${ingestStatus === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'}`}>
                            {ingestStatus === 'success' ? 'Result: ' : 'Error: '}{ingestMessage}
                        </div>
                    )}
                </div>
            </div>

            <CsvUploadFallback />

            <div className="bg-white border border-slate-200 rounded-2xl shadow-sm overflow-hidden">
                <div className="p-5 border-b border-slate-200 font-black text-sm text-slate-800 bg-slate-50 flex items-center justify-between">
                    <span>Run logs (Refreshes every 10s)</span>
                    <button
                        onClick={fetchRuns}
                        className="text-xs font-bold text-blue-600 hover:text-blue-700 px-3 py-1.5 rounded-lg hover:bg-blue-50 transition-colors"
                    >
                        Refresh Now
                    </button>
                </div>
                {isLoading ? (
                    <div className="p-12 text-center text-slate-400 font-medium animate-pulse">Loading run logs...</div>
                ) : (
                    <ScraperStatusTable initialRuns={runs} />
                )}
            </div>
        </div>
    )
}

import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";
import { InitializedAdapters } from "@/sources/registry";
import { executeIngestionTask } from "@/lib/ingest";

export async function POST(req: NextRequest) {
    try {
        const body = await req.json();
        const platform_id = parseInt(body.platform_id, 10);
        if (isNaN(platform_id)) {
            return NextResponse.json({ error: "Invalid platform_id format" }, { status: 400 });
        }

        const platform = await db.platform.findUnique({ where: { id: platform_id } });
        if (!platform) return NextResponse.json({ error: "Platform not found" }, { status: 404 });

        const adapterKey = platform.name.toLowerCase();
        const adapter = InitializedAdapters[adapterKey];

        if (!adapter) {
            return NextResponse.json({ error: "Adapter not implemented for this platform" }, { status: 501 });
        }

        // Trigger async
        executeIngestionTask(adapter, platform.id).catch(console.error);

        return NextResponse.json({ message: "Ingestion started" });
    } catch (err: any) {
        return NextResponse.json({ error: err.message }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";

export async function GET(req: NextRequest) {
    try {
        const searchParams = req.nextUrl.searchParams;
        const platform_id = searchParams.get('platform_id');
        const page = parseInt(searchParams.get('page') || '1', 10);
        const limit = parseInt(searchParams.get('limit') || '20', 10);

        const where = platform_id ? { platform_id: parseInt(platform_id, 10) } : {};
        const skip = (page - 1) * limit;

        const [data, total] = await Promise.all([
            db.ingestRun.findMany({
                where,
                orderBy: { start_time: 'desc' },
                skip,
                take: limit,
                include: { platform: true }
            }),
            db.ingestRun.count({ where })
        ]);

        return NextResponse.json({
            data,
            meta: {
                total,
                page,
                totalPages: Math.ceil(total / limit)
            }
        });
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { getTrendingCampaigns } from "@/lib/analytics";

export const dynamic = 'force-dynamic';

export async function GET() {
    try {
        const trending = await getTrendingCampaigns(6);
        const response = NextResponse.json({ data: trending });

        // Cache trending data for 5 minutes, stale for 1 hour
        response.headers.set('Cache-Control', 's-maxage=300, stale-while-revalidate=3600');

        return response;
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";
import { buildCampaignsQuery } from "@/lib/queryBuilder";

export async function GET(req: NextRequest) {
    try {
        const searchParams = req.nextUrl.searchParams;
        const qb = buildCampaignsQuery(searchParams);

        const toCompetitionRate = (campaign: any) => {
            const latest = campaign.snapshots?.[0];
            if (!latest) return Number.POSITIVE_INFINITY;

            const parsed = Number(latest.competition_rate);
            if (Number.isFinite(parsed)) return parsed;
            if (!latest.recruit_count || latest.recruit_count <= 0) return Number.POSITIVE_INFINITY;
            return latest.applicant_count / latest.recruit_count;
        };

        let data: any[] = [];
        let total = 0;

        if (qb.sort === 'competition_asc') {
            const all = await db.campaign.findMany({
                where: qb.where,
                orderBy: { created_at: 'desc' },
                include: {
                    platform: true,
                    snapshots: {
                        orderBy: { scraped_at: 'desc' },
                        take: 1
                    }
                }
            });

            const sorted = all.sort((a, b) => toCompetitionRate(a) - toCompetitionRate(b));
            total = sorted.length;
            data = sorted.slice(qb.skip, qb.skip + qb.limit);
        } else {
            [data, total] = await Promise.all([
                db.campaign.findMany({
                    where: qb.where,
                    orderBy: qb.orderBy as any,
                    skip: qb.skip,
                    take: qb.take,
                    include: {
                        platform: true,
                        snapshots: {
                            orderBy: { scraped_at: 'desc' },
                            take: 1
                        }
                    }
                }),
                db.campaign.count({ where: qb.where })
            ]);
        }

        const response = NextResponse.json({
            data,
            meta: {
                total,
                page: qb.page,
                totalPages: Math.ceil(total / qb.limit)
            }
        });

        // Vercel Edge Cache: Cache for 1 min, serving stale data for up to 10 mins while revalidating
        response.headers.set('Cache-Control', 's-maxage=60, stale-while-revalidate=600');

        return response;
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";
import { InitializedAdapters } from "@/sources/registry";
import { executeIngestionTask } from "@/lib/ingest";

export async function GET(req: NextRequest) {
    const authHeader = req.headers.get('authorization');
    const cronSecret = process.env.CRON_SECRET;

    if (authHeader !== `Bearer ${cronSecret}`) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    try {
        const activePlatforms = await db.platform.findMany({ where: { is_active: true } });

        const responses = activePlatforms.map(p => {
            const adapter = InitializedAdapters[p.name.toLowerCase()];
            if (adapter) {
                // Fire and forget so we don't timeout the cron request
                executeIngestionTask(adapter, p.id).catch(err => {
                    console.error(`Cron fail for ${p.name}:`, err);
                });
                return `Triggered ${p.name}`;
            }
            return `Skipped ${p.name} (no adapter)`;
        });

        return NextResponse.json({ message: "Cron triggered for platforms", details: responses });
    } catch (err: any) {
        return NextResponse.json({ error: err.message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";

export async function GET() {
    try {
        await db.$queryRaw`SELECT 1`;

        return NextResponse.json({
            status: 'ok',
            db: 'ok',
            timestamp: new Date().toISOString()
        });
    } catch (error: any) {
        return NextResponse.json({
            status: 'error',
            db: 'down',
            error: error?.message || 'database_unavailable',
            timestamp: new Date().toISOString()
        }, { status: 503 });
    }
}

"use client";

import Image from "next/image";
import Link from "next/link";
import { motion } from "framer-motion";
import { MapPin, Instagram, Bookmark, Play, MessageSquare, ArrowRight, TrendingUp } from "lucide-react";

export default function CampaignCard({ campaign }: { campaign: any }) {
    const snapshots = campaign.snapshots || [];
    const latest = snapshots[0] || {};
    const recruitCount = latest.recruit_count || 0;
    const applicantCount = latest.applicant_count || 0;
    const competitionRate = latest.competition_rate || (recruitCount > 0 ? applicantCount / recruitCount : 0);

    // Smooth progress for visualization
    const progress = recruitCount > 0 ? Math.min((applicantCount / recruitCount) * 100, 100) : 0;
    const isHot = competitionRate >= 2.0;

    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            whileHover={{ y: -8 }}
            className="group glass-card rounded-[2.5rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all duration-500 ease-out bg-white flex flex-col h-full border border-slate-100"
        >
            {/* Thumbnail Area */}
            <div className="relative h-64 overflow-hidden">
                {campaign.thumbnail_url ? (
                    <Image
                        src={campaign.thumbnail_url}
                        alt={campaign.title}
                        fill
                        sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 25vw"
                        className="object-cover group-hover:scale-110 transition-transform duration-1000 ease-[cubic-bezier(0.33,1,0.68,1)]"
                        priority={false}
                    />
                ) : (
                    <div className="w-full h-full bg-slate-50 flex items-center justify-center">
                        <Bookmark className="w-12 h-12 text-slate-200" />
                    </div>
                )}

                {/* Top Badges */}
                <div className="absolute top-5 left-5 flex flex-wrap gap-2 z-10">
                    <div className="px-4 py-2 rounded-2xl bg-black/60 backdrop-blur-xl border border-white/20 text-white text-[11px] font-bold tracking-tight uppercase shadow-2xl">
                        {campaign.platform?.name}
                    </div>
                    {isHot && (
                        <div className="px-4 py-2 rounded-2xl bg-rose-500/90 backdrop-blur-xl border border-rose-400/30 text-white text-[11px] font-black flex items-center gap-1.5 shadow-2xl shadow-rose-500/20">
                            <TrendingUp className="w-3.5 h-3.5" />
                            FAST TRENDING
                        </div>
                    )}
                </div>

                {/* Bottom Gradient for Contrast */}
                <div className="absolute inset-x-0 bottom-0 h-1/2 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
            </div>

            {/* Content Area */}
            <div className="p-7 flex flex-col flex-1 relative bg-white/50">
                {/* Media Icon & Type */}
                <div className="flex items-center gap-2 mb-4">
                    <div className="p-2 rounded-xl bg-slate-50 border border-slate-100 text-slate-400 group-hover:text-blue-600 group-hover:bg-blue-50 transition-colors">
                        {campaign.media_type === 'IP' ? <Instagram className="w-4 h-4" /> :
                            campaign.media_type === 'YP' ? <Play className="w-4 h-4" /> :
                                <MessageSquare className="w-4 h-4" />}
                    </div>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.1em]">
                        {campaign.media_type === 'IP' ? 'Instagram' :
                            campaign.media_type === 'YP' ? 'YouTube' : 'Naver Blog'}
                    </span>
                </div>

                <h3 className="font-bold text-[1.4rem] leading-[1.2] text-slate-900 group-hover:text-blue-700 transition-colors line-clamp-2 mb-4 tracking-tight">
                    {campaign.title}
                </h3>

                <div className="flex items-center gap-2 text-slate-500 mb-6">
                    <MapPin className="w-4 h-4" />
                    <span className="text-sm font-medium">{campaign.location || "지역 무관"}</span>
                </div>

                {/* Status Bar Section */}
                <div className="mb-8 p-5 rounded-[1.5rem] bg-slate-50/50 border border-slate-100 flex flex-col gap-3">
                    <div className="flex justify-between items-end">
                        <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Recruitment</span>
                        <div className="flex items-baseline gap-1">
                            <span className="text-lg font-black text-slate-900">{applicantCount}</span>
                            <span className="text-sm text-slate-400 font-bold">/ {recruitCount}</span>
                        </div>
                    </div>
                    {/* Visual Progress Bar */}
                    <div className="h-2 w-full bg-slate-200/50 rounded-full overflow-hidden">
                        <motion.div
                            initial={{ width: 0 }}
                            whileInView={{ width: `${progress}%` }}
                            transition={{ duration: 1, ease: "circOut" }}
                            className={`h-full rounded-full ${progress >= 100 ? 'bg-rose-500' : 'bg-blue-600'}`}
                        />
                    </div>
                </div>

                <Link href={`/campaigns/${campaign.id}`} className="mt-auto px-8 py-4 bg-slate-900 text-white rounded-[1.25rem] font-black text-sm flex items-center justify-center gap-2 group-hover:bg-blue-600 transition-all shadow-xl shadow-slate-900/10 hover:shadow-blue-600/20 active:scale-95">
                    View Campaign
                    <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                </Link>
            </div>
        </motion.div>
    );
}

