export default async function CampaignList({ searchParams }: { searchParams: { [key: string]: string | undefined } }) {
    const keyword = searchParams?.q?.toLowerCase() || "";
    const platformId = searchParams?.platform_id;
    const campaignType = searchParams?.campaign_type;
    const mediaType = searchParams?.media_type;
    const isFiltered = Boolean(keyword || platformId || campaignType || mediaType);

    let filtered: any[] = [];
    let trending: any[] = [];
    let dataMode: "ok" | "empty" | "unavailable" = "ok";

    try {
        const qb = buildCampaignsQuery(new URLSearchParams(searchParams as any));
        const toCompetitionRate = (campaign: any) => {
            const latest = campaign.snapshots?.[0];
            if (!latest) return Number.POSITIVE_INFINITY;
            const parsed = Number(latest.competition_rate);
            if (Number.isFinite(parsed)) return parsed;
            return latest.applicant_count / (latest.recruit_count || 1);
        };

        if (qb.sort === "competition_asc") {
            const [all, trendData] = await Promise.all([
                db.campaign.findMany({
                    where: qb.where,
                    orderBy: { created_at: "desc" },
                    include: { platform: true, snapshots: { orderBy: { scraped_at: "desc" }, take: 1 } },
                }),
                getTrendingCampaigns(4),
            ]);
            filtered = all.sort((a, b) => toCompetitionRate(a) - toCompetitionRate(b)).slice(qb.skip, qb.skip + qb.limit);
            trending = trendData;
        } else {
            [filtered, trending] = await Promise.all([
                db.campaign.findMany({
                    where: qb.where,
                    orderBy: qb.orderBy as any,
                    skip: qb.skip,
                    take: qb.take,
                    include: { platform: true, snapshots: { orderBy: { scraped_at: "desc" }, take: 1 } },
                }),
                getTrendingCampaigns(4),
            ]);
        }
    } catch (error) {
        console.error("Database connection failed, falling back to mock data.", error);
        dataMode = "unavailable";
        filtered = MOCK_CAMPAIGNS;
        trending = MOCK_CAMPAIGNS.slice(0, 4);
    }

    if (dataMode === "ok" && !isFiltered && filtered.length === 0) {
        dataMode = "empty";
    }

    return (
        <div className="flex flex-col gap-8">
            {dataMode === "unavailable" ? (
                <div className="rounded-2xl border border-amber-200 bg-amber-50 px-4 py-3 text-amber-900 text-sm font-bold">
                    Database is unavailable. Showing fallback data.
                </div>
            ) : null}

            {dataMode === "empty" ? (
                <div className="rounded-2xl border border-slate-200 bg-white px-4 py-3 text-slate-700 text-sm">
                    Database is reachable but no campaigns were found. Run ingestion to populate data.
                </div>
            ) : null}

            {!isFiltered && dataMode === "ok" && (
                <div className="flex flex-col gap-4">
                    <div className="flex items-center gap-2">
                        <span className="bg-rose-500 text-white text-xs font-black px-2 py-1 rounded-md animate-pulse">TRENDING</span>
                        <h2 className="text-xl font-black text-slate-800">Trending campaigns</h2>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                        {trending.map((c) => (
                            <CampaignCard key={`trend-${c.id}`} campaign={c} />
                        ))}
                    </div>
                </div>
            )}

            <div className="mt-4">
                <div className="flex justify-between items-end mb-6">
                    <div className="font-bold text-slate-700 text-lg">
                        Total <span className="text-blue-600">{filtered.length}</span> campaigns
                    </div>
                </div>

                {filtered.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {filtered.map((campaign) => (
                            <CampaignCard key={campaign.id} campaign={campaign} />
                        ))}
                    </div>
                ) : (
                    <div className="py-32 flex flex-col items-center justify-center text-center bg-white rounded-2xl border border-dashed border-slate-300">
                        <div className="text-slate-400 mb-2">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path
                                    strokeLinecap="round"
                                    strokeLinejoin="round"
                                    strokeWidth={1}
                                    d="M9.172 16.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"
                                />
                            </svg>
                        </div>
                        <h3 className="text-xl font-bold text-slate-700 mb-1">No campaigns found</h3>
                        <p className="text-slate-500">Try changing filters or try again after ingestion.</p>
                    </div>
                )}
            </div>
        </div>
    );
}

import axios, { AxiosRequestConfig, AxiosResponse } from 'axios';

/**
 * Enhanced fetcher with exponential backoff and retry logic.
 * Default: 3 retries, starting at 1000ms delay.
 */
export async function fetchWithRetry(
    url: string,
    options?: AxiosRequestConfig,
    maxRetries: number = 3,
    baseDelayMs: number = 1000
): Promise<AxiosResponse> {
    let attempt = 0;

    while (attempt < maxRetries) {
        try {
            return await axios.get(url, {
                ...options,
                timeout: options?.timeout || 15000,
            });
        } catch (error: any) {
            attempt++;

            // Only retry on certain errors: Network timeouts, 5xx server errors, or generic ECONNRESETs
            const isRetryable =
                !error.response ||
                (error.response.status >= 500 && error.response.status < 600) ||
                error.code === 'ECONNABORTED' ||
                error.code === 'ECONNRESET';

            if (!isRetryable || attempt >= maxRetries) {
                throw error;
            }

            // Exponential backoff with jitter
            const delay = baseDelayMs * Math.pow(2, attempt - 1) + Math.random() * 500;
            console.warn(`[Fetcher] Request failed: ${error.message}. Retrying (${attempt}/${maxRetries}) in ${Math.round(delay)}ms... -> ${url}`);

            await new Promise(res => setTimeout(res, delay));
        }
    }

    throw new Error("fetchWithRetry: Impossible state reached.");
}

import { db } from "./db";
import { processAndDedupeCampaign } from "@/sources/normalize";
import { IPlatformAdapter } from "@/sources/types";

export async function executeIngestionTask(adapter: IPlatformAdapter, platformId: number) {
    // Creating initial IngestRun Tracking record
    const run = await db.ingestRun.create({
        data: {
            platform_id: platformId,
            status: 'RUNNING'
        }
    });

    let addedCount = 0;
    let updatedCount = 0;

    try {
        // Fetch up to 5 pages for the MVP ingestion run
        for (let page = 1; page <= 5; page++) {
            const results = await adapter.fetchList(page);
            if (!results || results.length === 0) break;

            const promises = results.map(async (item) => {
                const res = await processAndDedupeCampaign(platformId, item);
                if (res.status === 'created') addedCount++;
                else updatedCount++;
            });
            const outcomes = await Promise.allSettled(promises);
            outcomes.forEach((outcome, idx) => {
                if (outcome.status === 'rejected') {
                    console.error(`Error processing item ${results[idx].original_id}:`, outcome.reason);
                }
            });

            // Optional: small delay between pages to avoid rate limiting
            await new Promise(resolve => setTimeout(resolve, 500));
        }

        await db.ingestRun.update({
            where: { id: run.id },
            data: {
                status: 'SUCCESS',
                end_time: new Date(),
                records_added: addedCount,
                records_updated: updatedCount
            }
        });
        return { success: true, run_id: run.id, added: addedCount, updated: updatedCount };
    } catch (e: any) {
        await db.ingestRun.update({
            where: { id: run.id },
            data: {
                status: 'FAILED',
                end_time: new Date(),
                error_log: e.message || String(e)
            }
        });
        return { success: false, run_id: run.id, error: e.message };
    }
}

